      .replace(/[#*`~]/g, '')           // Hapus header, bold, code, italic
      .replace(/\[(.*?)\]\(.*?\)/g, '$1') // Ambil teks dari Link saja
      .replace(/>\s+/g, '')              // Hapus blockquote
      .replace(/[-*]\s+/g, '')           // Hapus bullet points
      .replace(/"/g, "'") 
      .trim();

    // 2. Ubah semua newline (\n) menjadi <br>
    plainText = plainText.replace(/\n/g, '<br><br>');

    // Simpan hasil ke field baru: plain_text_1, plain_text_2, dst.
    item.json[`plain_text_${i}`] = plainText;
  }
}

return [item];

